const input = $json.body || $json || {};

function clean(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function normalized(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toArray(value) {
  if (Array.isArray(value)) return value.map((item) => clean(item)).filter(Boolean);
  const text = clean(value);
  return text ? [text] : [];
}

function normalizeProbability(value) {
  const text = normalized(value);
  if (!text) return '';
  if (/alta/.test(text)) return 'Alta';
  if (/media/.test(text)) return 'Media';
  if (/baja/.test(text)) return 'Baja';
  return clean(value);
}

const rawContext = input.context && typeof input.context === 'object' && !Array.isArray(input.context)
  ? input.context
  : {};

const context = {
  stage: clean(rawContext.stage || rawContext.level || rawContext.nivel || rawContext.etapa),
  subject: clean(rawContext.subject || rawContext.materia || rawContext.asignatura),
  duration: clean(rawContext.duration || rawContext.duracion || rawContext.tiempo)
};

const rawActivity = input.activity && typeof input.activity === 'object' && !Array.isArray(input.activity)
  ? input.activity
  : {};

const activity = {
  ...rawActivity,
  title: clean(rawActivity.title || rawActivity.taskTitle || rawActivity.activityTitle || rawActivity.name),
  objective: clean(rawActivity.objective || rawActivity.goal || rawActivity.description),
  steps: toArray(rawActivity.steps || rawActivity.instructions),
  assessment: toArray(rawActivity.assessment || rawActivity.evaluation),
  resources_required: toArray(rawActivity.resources_required || rawActivity.resources || rawActivity.materials),
  closure: clean(rawActivity.closure || rawActivity.conclusion)
};

const supportedActions = {
  expert_debate: {
    mode: 'json',
    systemPrompt: 'Analiza una actividad didactica desde tres perspectivas expertas complementarias. Devuelve solo JSON valido con un array de 3 objetos usando las claves exactas: expert, role, pros, cons.'
  },
  stress_test: {
    mode: 'json',
    systemPrompt: 'Evalua riesgos reales de aula. Devuelve solo JSON valido con este shape exacto: {"score":0,"risks":[{"event":"","probability":"Alta|Media|Baja","extinguisher":""}]}. score debe ser entero de 0 a 100.'
  },
  curriculum_mapping: {
    mode: 'markdown',
    systemPrompt: 'Mapea la actividad al marco LOMLOE. Devuelve solo Markdown estructurado con secciones breves y accionables para docente.'
  },
  parent_summary: {
    mode: 'markdown',
    systemPrompt: 'Resume la actividad para familias en lenguaje claro, sin jerga pedagogica. Devuelve solo texto o Markdown breve y comprensible.'
  },
  critic_mirror: {
    mode: 'json',
    systemPrompt: 'Haz una critica honesta de la actividad. Devuelve solo JSON valido con estas claves exactas: elephant, bias, placebo_effect, suggestion.'
  }
};

const action = clean(input.action);
const actionConfig = supportedActions[action] || null;

let shouldCallModel = true;
let response = null;
if (!clean(input.sessionId)) {
  shouldCallModel = false;
  response = {
    ok: false,
    type: 'validation_error',
    data: null,
    message: 'sessionId is required.',
    error: {
      code: 'SESSION_ID_REQUIRED',
      message: 'The lab workflow requires a non-empty sessionId.'
    }
  };
} else if (!action) {
  shouldCallModel = false;
  response = {
    ok: false,
    type: 'validation_error',
    data: null,
    message: 'action is required.',
    error: {
      code: 'ACTION_REQUIRED',
      message: 'The lab workflow requires an action.'
    }
  };
} else if (!actionConfig) {
  shouldCallModel = false;
  response = {
    ok: false,
    type: 'validation_error',
    data: null,
    message: 'Unsupported lab action.',
    error: {
      code: 'UNSUPPORTED_ACTION',
      message: 'The provided action is not supported by the lab workflow.'
    }
  };
} else if (!activity.title) {
  shouldCallModel = false;
  response = {
    ok: false,
    type: 'validation_error',
    data: null,
    message: 'activity.title is required.',
    error: {
      code: 'ACTIVITY_TITLE_REQUIRED',
      message: 'The lab workflow requires activity.title with meaningful content.'
    }
  };
}

return [{
  json: {
    sessionId: clean(input.sessionId),
    action,
    actionConfig,
    activity,
    context,
    requestedAt: clean(input.timestamp) || new Date().toISOString(),
    shouldCallModel,
    validationResponse: response,
    helpers: {
      normalizeProbabilityExample: normalizeProbability('alta')
    }
  }
}];

const config = {
  lmStudioUrl: 'https://realtor-employee-cafe-offshore.trycloudflare.com/v1/chat/completions',
  lmStudioKey: 'CHANGE_ME_LM_STUDIO_TOKEN',
  lmModel: 'google/gemma-4-e2b',
  timeout: 45000
};

return [{ json: { ...$json, config } }];

